Here's a complete C program that reads candidate names and votes from a file `votes.txt`, evaluates the election results, and writes the output to `resultats.txt` following the specified format.

**Assumptions:**
- The file `votes.txt` contains candidate names first, one per line.
- After all candidate names, the votes follow, one per line.
- A vote is an integer representing the candidate number (1-based).
- Invalid votes are those that do not correspond to any candidate number.
- The program reads until EOF.
- The maximum number of candidates is assumed to be 100 for simplicity.

---

### Sample `votes.txt` example

```
Alice
Bob
Charlie
Diana
Eve
Frank
Grace
1
2
3
4
5
6
7
8
9
3
5
...
```

---

### C program: `election.c`

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_CANDIDATES 100
#define MAX_NAME_LEN 100

int main() {
    FILE *fin = fopen("votes.txt", "r");
    FILE *fout = fopen("resultats.txt", "w");

    if (!fin) {
        fprintf(stderr, "Error opening votes.txt\n");
        return 1;
    }
    if (!fout) {
        fprintf(stderr, "Error opening resultats.txt\n");
        fclose(fin);
        return 1;
    }

    char line[256];
    char candidates[MAX_CANDIDATES][MAX_NAME_LEN];
    int candidate_count = 0;

    // First read candidate names until we reach a line that is not a name
    // We assume candidate names do not start with digits only.
    // We'll identify votes as lines that can be converted to integers.
    // So first read all lines, store them in a temp array, then separate names and votes.

    // Instead, let's read all lines into memory first
    #define MAX_LINES 1000
    char *lines[MAX_LINES];
    int lines_count = 0;

    while (fgets(line, sizeof(line), fin) != NULL) {
        // Remove trailing newline
        line[strcspn(line, "\r\n")] = 0;
        if (strlen(line) == 0) continue; // skip empty lines

        lines[lines_count] = malloc(strlen(line) + 1);
        if (!lines[lines_count]) {
            fprintf(stderr, "Memory allocation error\n");
            // free previous lines
            for (int i = 0; i < lines_count; i++) free(lines[i]);
            fclose(fin);
            fclose(fout);
            return 1;
        }
        strcpy(lines[lines_count], line);
        lines_count++;
        if (lines_count >= MAX_LINES) break;
    }
    fclose(fin);

    // Now separate candidates and votes
    // Candidates are at the beginning, all lines that are NOT pure integers
    // Once we hit a line that is a pure integer, from that line on are votes

    int i = 0;
    for (; i < lines_count; i++) {
        char *p = lines[i];
        // Check if line is an integer
        char *endptr;
        long val = strtol(p, &endptr, 10);
        if (*endptr == '\0') {
            // line is a pure integer
            break;
        }
        // else this is candidate name
        if (candidate_count >= MAX_CANDIDATES) {
            fprintf(stderr, "Too many candidates (max %d)\n", MAX_CANDIDATES);
            // free lines
            for (int j = 0; j < lines_count; j++) free(lines[j]);
            fclose(fout);
            return 1;
        }
        strncpy(candidates[candidate_count], p, MAX_NAME_LEN - 1);
        candidates[candidate_count][MAX_NAME_LEN - 1] = '\0';
        candidate_count++;
    }

    if (candidate_count == 0) {
        fprintf(stderr, "No candidates found in votes.txt\n");
        for (int j = 0; j < lines_count; j++) free(lines[j]);
        fclose(fout);
        return 1;
    }

    // Now votes start from i to lines_count-1
    int *votes = malloc(sizeof(int) * (lines_count - i));
    if (!votes) {
        fprintf(stderr, "Memory allocation error\n");
        for (int j = 0; j < lines_count; j++) free(lines[j]);
        fclose(fout);
        return 1;
    }
    int votes_count = 0;
    for (int j = i; j < lines_count; j++) {
        char *p = lines[j];
        char *endptr;
        long val = strtol(p, &endptr, 10);
        if (*endptr != '\0') {
            // This line is not integer? Ignore or treat as invalid vote?
            // Let's treat as invalid vote with invalid number
            val = -1;
        }
        votes[votes_count++] = (int)val;
    }

    // Clean up lines memory
    for (int j = 0; j < lines_count; j++) free(lines[j]);

    // Process votes
    int *candidate_scores = calloc(candidate_count, sizeof(int));
    if (!candidate_scores) {
        fprintf(stderr, "Memory allocation error\n");
        free(votes);
        fclose(fout);
        return 1;
    }

    int invalid_votes = 0;
    int valid_votes = 0;

    for (int j = 0; j < votes_count; j++) {
        int v = votes[j];
        if (v < 1 || v > candidate_count) {
            // invalid vote
            fprintf(fout, "Invalid vote: %d\n", v);
            invalid_votes++;
        } else {
            candidate_scores[v - 1]++;
            valid_votes++;
        }
    }

    int total_votes = valid_votes + invalid_votes;

    fprintf(fout, "Number of voters: %d\n", total_votes);
    fprintf(fout, "Number of valid votes: %d\n", valid_votes);
    fprintf(fout, "Number of invalid votes: %d\n\n", invalid_votes);

    fprintf(fout, "Candidate score\n");
    for (int c = 0; c < candidate_count; c++) {
        fprintf(fout, "Candidate %d %s %d\n", c + 1, candidates[c], candidate_scores[c]);
    }
    fprintf(fout, "\n");

    // Determine winner(s)
    int max_score = 0;
    for (int c = 0; c < candidate_count; c++) {
        if (candidate_scores[c] > max_score) max_score = candidate_scores[c];
    }

    fprintf(fout, "The winners:\n");
    for (int c = 0; c < candidate_count; c++) {
        if (candidate_scores[c] == max_score) {
            fprintf(fout, "Candidate %d %s\n", c + 1, candidates[c]);
        }
    }

    // Clean up
    free(candidate_scores);
    free(votes);
    fclose(fout);

    return 0;
}
```

